UPDATE articles SET content = '[{"id":"q1","type":"paragraph","text":"Майнинг-ферма — это устанавливаемый предмет **«Компьютерная станция»**, в который игрок размещает комплектующие (для добычи) и охлаждение (для контроля температуры). Ферма генерирует прогресс и выдаёт награду — **майнинг монеты**, которые можно обменять на **DP**."},{"id":"q2","type":"heading2","text":"🔧 Установка фермы"},{"id":"q3","type":"step","stepNum":1,"text":"Установите **компьютерную станцию** в удобное место."},{"id":"q4","type":"step","stepNum":2,"text":"Подключите её к устройству, выделяющему `100 электрической энергии`."},{"id":"q5","type":"step","stepNum":3,"text":"Сядьте за стол и нажмите кнопку **«Открыть меню управления фермой»**."},{"id":"q6","type":"step","stepNum":4,"text":"Готово! Сложите комплектующие в **лутбокс на столе** и начинайте майнинг."},{"id":"q7","type":"heading2","text":"⚙️ Как работает добыча"},{"id":"q8","type":"paragraph","text":"Каждые **60 секунд** происходит тик — обновление фермы:"},{"id":"q9","type":"list","ordered":false,"items":["Добавляется прогресс от установленных комплектующих","Меняется температура (нагрев + охлаждение)","Списывается прочность предметов (износ)"]},{"id":"q10","type":"paragraph","text":"У каждого комплектующего есть своя мощность. Когда прогресс достигает **100%** — выдаётся награда в виде майнинг монет."},{"id":"q11","type":"heading2","text":"🌡️ Температура и перегрев"},{"id":"q12","type":"paragraph","text":"Комплектующие **добавляют** температуру, охлаждение **снижает** её. Каждый тик добавляет базовую температуру."},{"id":"q13","type":"warning","icon":"Перегрев и взрыв!","text":"Если температура достигнет **150 градусов** — ферма **взрывается** и вы теряете все ресурсы без возможности их вернуть. Следите за охлаждением!"},{"id":"q14","type":"heading2","text":"🔩 Слоты и комплектующие"},{"id":"q15","type":"paragraph","text":"Количество слотов зависит от привилегии. Обычный игрок — **6 слотов** под комплектующие. Донат-привилегии расширяют лимит до **42 слотов**."},{"id":"q16","type":"warning","icon":"Важно про слоты!","text":"**1 слот всегда оставляйте пустым!** В нём будут появляться майнинг монеты."},{"id":"q17","type":"heading2","text":"📦 Категории предметов"},{"id":"q18","type":"list","ordered":false,"items":["**Комплектующие (добыча):** дают прогресс, но повышают температуру и тратят прочность — видеокарты, хеш-модули, контроллеры, память, питание","**Охлаждение (стабильность):** снижает температуру — вентиляторы, радиаторы, водяное охлаждение, чиллеры"]},{"id":"q19","type":"heading2","text":"💡 Примеры сборок"},{"id":"q20","type":"step","stepNum":1,"text":"**Бюджетная** (для новичков): 2× Бюджетная видеокарта + 1× Райзер-адаптер + 2× Двойной вентилятор"},{"id":"q21","type":"step","stepNum":2,"text":"**Сбалансированная** (без перегревов): 2× Модуль хеш-платы + 1× Контроллер майнинга + 2× Усиленная водянка"},{"id":"q22","type":"tip","icon":"Где получить комплектующие?","text":"Кастомный крафт в **личном меню** `/m`, дроп из ящиков и бочек, ивенты (рейдбазы, конвой, караван), **внутриигровой магазин** `/shop` или **донат-магазин**."},{"id":"q23","type":"tip","icon":"Лучшая стратегия","text":"Баланс между добычей и охлаждением. Слишком много комплектующих без охлаждения — взрыв. Слишком много охлаждения — медленный прогресс. Следите за фермой чаще, если используете слабые комплектующие!"}]' WHERE id = 17;
